        indexed.sort((a, b) => b.confidence - a.confidence);
        const topK = indexed.slice(0, SECURITY_CONFIG.topK);

        // DEFENSE 2: Add differential privacy noise
        const noisyResults = topK.map(item => ({
            class: item.class,
            confidence: Math.max(0, Math.min(1,
                addLaplaceNoise(item.confidence, SECURITY_CONFIG.noiseScale)
            ))
        }));

        // DEFENSE 3: Round confidence scores
        const roundedResults = noisyResults
            .filter(r => r.confidence >= SECURITY_CONFIG.confidenceThreshold)
            .map(r => ({
                class: r.class,
                confidence: Math.round(r.confidence * 100) / 100
            }));

