const CUSTOMER_TIERS = {
    free: {
        dailyLimit: 100,
        batchSize: 1,
        topK: 1,
        noiseScale: 0.1,
        rateLimitPerMinute: 10
    },
    enterprise: {
        dailyLimit: 100000,
        batchSize: 100,
        topK: 5,
        noiseScale: 0.02,
        rateLimitPerMinute: 1000
    },
    premium: {
        dailyLimit: 1000000,
        batchSize: 500,
        topK: 10,
        noiseScale: 0.01,
        rateLimitPerMinute: 5000
    }
};

// Anomaly detection thresholds
const ANOMALY_CONFIG = {
    similarQueryThreshold: 0.85,  // Cosine similarity threshold
    burstWindowMs: 60000,
    burstThreshold: 50,
    suspiciousPatternWindow: 3600000,  // 1 hour
    gradientAttackPatternThreshold: 100
};

class ModelInversionDetector {
    constructor(redis) {
        this.redis = redis;
    }

    async analyzeQueryPattern(customerId, inputHash, inputEmbedding) {
        const key = `query_history:${customerId}`;
        const recentQueries = await this.redis.lrange(key, 0, 999);

        let suspicionScore = 0;
        let similarQueryCount = 0;
        let gradientPatternCount = 0;

        for (const queryJson of recentQueries) {
            const query = JSON.parse(queryJson);

            // Check for similar queries (potential gradient estimation)
            const similarity = this.cosineSimilarity(inputEmbedding, query.embedding);
            if (similarity > ANOMALY_CONFIG.similarQueryThreshold) {
                similarQueryCount++;
            }

            // Detect systematic exploration patterns
            if (this.detectGradientPattern(inputEmbedding, query.embedding)) {
                gradientPatternCount++;
            }
        }

        // Calculate suspicion score
        if (similarQueryCount > 10) suspicionScore += 30;
        if (gradientPatternCount > ANOMALY_CONFIG.gradientAttackPatternThreshold) {
            suspicionScore += 50;
        }

        // Store current query for future analysis
        await this.redis.lpush(key, JSON.stringify({
            hash: inputHash,
            embedding: inputEmbedding,
            timestamp: Date.now()
        }));
        await this.redis.ltrim(key, 0, 999);
        await this.redis.expire(key, 86400);  // 24 hour retention

        return {
            suspicionScore,
            similarQueryCount,
            gradientPatternCount,
            isHighRisk: suspicionScore > 70
        };
    }

    cosineSimilarity(a, b) {
        if (!a || !b || a.length !== b.length) return 0;
        let dotProduct = 0, normA = 0, normB = 0;
        for (let i = 0; i < a.length; i++) {
            dotProduct += a[i] * b[i];
            normA += a[i] * a[i];
            normB += b[i] * b[i];
        }
        return dotProduct / (Math.sqrt(normA) * Math.sqrt(normB));
    }

    detectGradientPattern(current, previous) {
        // Detect small systematic perturbations typical of gradient attacks
        if (!current || !previous) return false;
        let smallPerturbations = 0;
        for (let i = 0; i < current.length; i++) {
            const diff = Math.abs(current[i] - previous[i]);
            if (diff > 0.001 && diff < 0.05) smallPerturbations++;
        }
        return smallPerturbations > current.length * 0.8;
    }
}

const inversionDetector = new ModelInversionDetector(redis);

// Authentication middleware
async function authenticateRequest(req, res, next) {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
        return res.status(401).json({ error: 'Authentication required' });
    }

    try {
        const token = authHeader.substring(7);
        const decoded = jwt.verify(token, process.env.JWT_SECRET);

        // Get customer tier from database/cache
        const customerData = await redis.hgetall(`customer:${decoded.customerId}`);
        if (!customerData || !customerData.tier) {
