                    securityLogger.error('Potential model inversion attack detected', {
                        requestId,
                        customerId: customer.id,
                        suspicionScore: anomalyResult.suspicionScore,
                        similarQueries: anomalyResult.similarQueryCount,
                        gradientPatterns: anomalyResult.gradientPatternCount
                    });

                    // Increase noise for suspicious requests
                    customer.config = {
                        ...customer.config,
                        noiseScale: 0.3,
                        topK: 1
                    };
                }

                // Make prediction with security controls
                const predictions = model.predict(inputTensor);
                const probabilities = await predictions.array();

                const securedResult = applySecurityControls(
                    probabilities[0],
                    customer.config
                );

                results.push({
                    index: results.length,
                    predictions: securedResult
                });

                inputTensor.dispose();
                predictions.dispose();
            }

            // Audit log for all predictions
            securityLogger.info('Batch prediction completed', {
                requestId,
                customerId: customer.id,
                batchSize: images.length,
                processingTimeMs: Date.now() - startTime,
                anomalyDetected
            });

            res.json({
                requestId,
                results,
                metadata: {
                    processedAt: new Date().toISOString(),
                    quotaRemaining: await getQuotaRemaining(customer.id)
                }
            });

        } catch (error) {
            securityLogger.error('Prediction error', {
                requestId,
                customerId: customer.id,
                error: error.message
            });
            res.status(500).json({
                requestId,
                error: 'Prediction failed'
            });
        }
    }
);

function applySecurityControls(probabilities, config) {
    // Top-K filtering
    const indexed = probabilities.map((p, i) => ({ class: i, confidence: p }));
    indexed.sort((a, b) => b.confidence - a.confidence);
    const topK = indexed.slice(0, config.topK);

    // Apply differential privacy noise
    const noisy = topK.map(item => ({
        class: item.class,
        confidence: Math.max(0, Math.min(1,
            item.confidence + laplaceMechanism(config.noiseScale)
        ))
    }));

    // Round and filter
    return noisy
        .filter(r => r.confidence >= 0.05)
        .map(r => ({
            class: r.class,
            confidence: Math.round(r.confidence * 100) / 100
        }));
}

function laplaceMechanism(scale) {
    const u = Math.random() - 0.5;
    return scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
}

async function extractEmbedding(tensor) {
    // Extract intermediate layer for similarity comparison
    const embedding = await tensor.mean([1, 2]).array();
    return embedding[0];
}

async function getQuotaRemaining(customerId) {
    const used = await redis.get(`ratelimit:daily:${customerId}`) || 0;
    const tier = (await redis.hget(`customer:${customerId}`, 'tier')) || 'free';
    return CUSTOMER_TIERS[tier].dailyLimit - parseInt(used);
}
