**SECURE VERSION**:

```javascript
const tf = require('@tensorflow/tfjs-node');
const crypto = require('crypto');
const axios = require('axios');
const fs = require('fs').promises;
const path = require('path');

// Trusted model registry with verified hashes
const TRUSTED_MODEL_REGISTRY = {
  'sentiment-v1': {
    url: 'https://models.company.com/sentiment-v1/model.json',
    sha256: 'a3b2c1d4e5f6789012345678901234567890abcdef1234567890abcdef123456',
    allowedOps: ['Dense', 'Conv2D', 'Flatten', 'Dropout', 'BatchNormalization'],
    maxSizeMB: 100,
    version: '1.2.0'
  }
};

class SecureModelLoader {
  constructor(options = {}) {
    this.modelDir = options.modelDir || './models/verified';
    this.disallowedOps = ['Lambda', 'PyFunc', 'CustomOp'];
    this.maxModelSize = options.maxSizeMB || 500;
  }

  async loadTrustedModel(modelId) {
    const modelConfig = TRUSTED_MODEL_REGISTRY[modelId];
    if (!modelConfig) {
      throw new Error(`Model '${modelId}' not in trusted registry`);
    }

    // Download with size limits
    const modelData = await this.downloadWithLimits(
      modelConfig.url,
      modelConfig.maxSizeMB * 1024 * 1024
    );

    // Verify cryptographic hash
    const hash = crypto.createHash('sha256').update(modelData).digest('hex');
    if (hash !== modelConfig.sha256) {
      console.error(`Hash mismatch for ${modelId}: expected ${modelConfig.sha256}, got ${hash}`);
      throw new Error('Model integrity verification failed');
    }

    // Parse and validate model structure
    const modelJson = JSON.parse(modelData.toString());
    this.validateModelStructure(modelJson, modelConfig.allowedOps);

    // Save to verified directory
    const modelPath = path.join(this.modelDir, modelId, 'model.json');
    await fs.mkdir(path.dirname(modelPath), { recursive: true });
    await fs.writeFile(modelPath, modelData);

    console.log(`Verified and loaded model: ${modelId} (v${modelConfig.version})`);
    return tf.loadLayersModel(`file://${modelPath}`);
  }

  async downloadWithLimits(url, maxBytes) {
    const response = await axios.get(url, {
      responseType: 'arraybuffer',
      maxContentLength: maxBytes,
      timeout: 30000
    });

    if (response.data.length > maxBytes) {
      throw new Error(`Model exceeds size limit: ${response.data.length} > ${maxBytes}`);
    }
    return Buffer.from(response.data);
  }

  validateModelStructure(modelJson, allowedOps) {
    const layers = modelJson.modelTopology?.config?.layers || [];

    for (const layer of layers) {
      const className = layer.class_name;

      // Block dangerous layer types
      if (this.disallowedOps.includes(className)) {
        throw new Error(`Disallowed layer type detected: ${className}`);
      }

      // Verify only allowed operations
      if (allowedOps && !allowedOps.includes(className)) {
        throw new Error(`Unexpected layer type: ${className}`);
      }
    }
  }
}

// Usage
const loader = new SecureModelLoader();
const model = await loader.loadTrustedModel('sentiment-v1');
```

**Key Security Controls**:
- **Trusted Registry**: Only models explicitly whitelisted with verified hashes can be loaded
- **Cryptographic Integrity**: SHA-256 verification ensures model files haven't been tampered
- **Layer Validation**: Blocks dangerous layer types (Lambda, PyFunc) that can execute arbitrary code
- **Size Limits**: Prevents resource exhaustion attacks from oversized models
- **Allowlist Approach**: Only permitted layer types are accepted, blocking unknown operations

Third-party model hubs like Hugging Face have become attack vectors for malicious models. In 2024, researchers discovered over 100 malicious models on Hugging Face containing hidden backdoors and data exfiltration code. Here's a production-grade approach for secure model hub integration.

**PRODUCTION PATTERN**:

```javascript
const crypto = require('crypto');
const axios = require('axios');
const fs = require('fs').promises;
const path = require('path');
const { VM } = require('vm2');
const EventEmitter = require('events');

class SecureModelHubClient extends EventEmitter {
  constructor(config) {
    super();
    this.config = {
      cacheDir: config.cacheDir || './model-cache',
      quarantineDir: config.quarantineDir || './model-quarantine',
      allowedOrganizations: config.allowedOrganizations || [],
      requireSignedModels: config.requireSignedModels !== false,
      scanTimeout: config.scanTimeout || 60000,
      maxModelSize: config.maxModelSize || 5 * 1024 * 1024 * 1024, // 5GB
      huggingFaceToken: config.huggingFaceToken,
      auditLog: config.auditLog || console
    };

    this.maliciousPatterns = [
      /require\s*\(['"]child_process['"]/,
      /exec\s*\(/,
      /spawn\s*\(/,
      /eval\s*\(/,
      /Function\s*\(/,
      /\.readFileSync\s*\(/,
      /\.writeFileSync\s*\(/,
      /process\.env/,
      /\bfetch\s*\(/,
      /XMLHttpRequest/,
      /WebSocket/,
      /pickle\.loads/,
      /__reduce__/,
      /__import__/
    ];

    this.blockedFileTypes = [
      '.pkl', '.pickle', '.pt', '.pth',  // Can contain arbitrary Python code
      '.bin'  // Binary files need extra scrutiny
    ];
  }

  async fetchModelSecurely(repoId, options = {}) {
    const auditId = crypto.randomUUID();
    const startTime = Date.now();

    try {
      // Step 1: Validate repository identity
      this.auditLog('model_fetch_start', {
        auditId,
        repoId,
        timestamp: new Date().toISOString()
      });

      const repoInfo = await this.validateRepository(repoId);

      // Step 2: Organization allowlist check
      if (!this.isOrganizationAllowed(repoInfo.author)) {
        throw new SecurityError(
          `Organization '${repoInfo.author}' not in allowlist`,
          'UNAUTHORIZED_ORG'
        );
      }

      // Step 3: Check model signature (if required)
      if (this.config.requireSignedModels) {
        await this.verifyModelSignature(repoId, repoInfo);
      }

      // Step 4: Download to quarantine
      const quarantinePath = await this.downloadToQuarantine(repoId, repoInfo);

      // Step 5: Deep security scan
      const scanResult = await this.performSecurityScan(quarantinePath, repoId);

      if (!scanResult.safe) {
        await this.handleMaliciousModel(quarantinePath, scanResult, auditId);
        throw new SecurityError(
          `Security scan failed: ${scanResult.threats.join(', ')}`,
          'SECURITY_SCAN_FAILED'
        );
      }

      // Step 6: Move to verified cache
      const verifiedPath = await this.moveToVerifiedCache(quarantinePath, repoId);

      // Step 7: Create secure manifest
      const manifest = await this.createSecureManifest(verifiedPath, repoId, repoInfo);

      this.auditLog('model_fetch_success', {
        auditId,
        repoId,
        duration: Date.now() - startTime,
        manifest: manifest.hash
      });

      return { path: verifiedPath, manifest };

    } catch (error) {
      this.auditLog('model_fetch_failed', {
        auditId,
        repoId,
        error: error.message,
        errorCode: error.code,
        duration: Date.now() - startTime
      });
      throw error;
    }
  }

  async validateRepository(repoId) {
    const [author, modelName] = repoId.split('/');

    if (!author || !modelName) {
      throw new SecurityError('Invalid repository ID format', 'INVALID_REPO_ID');
    }

    // Fetch repository metadata from Hugging Face API
    const response = await axios.get(
      `https://huggingface.co/api/models/${repoId}`,
      {
        headers: this.config.huggingFaceToken ? {
          'Authorization': `Bearer ${this.config.huggingFaceToken}`
        } : {},
        timeout: 10000
      }
    );

    const repoInfo = response.data;

    // Check for security indicators
    if (repoInfo.disabled) {
      throw new SecurityError('Model has been disabled by Hugging Face', 'MODEL_DISABLED');
    }

    if (repoInfo.gated && !this.config.huggingFaceToken) {
      throw new SecurityError('Gated model requires authentication', 'AUTH_REQUIRED');
    }

    return {
      author,
      modelName,
      sha: repoInfo.sha,
      lastModified: repoInfo.lastModified,
      downloads: repoInfo.downloads,
      likes: repoInfo.likes,
      tags: repoInfo.tags || [],
      siblings: repoInfo.siblings || []
    };
  }

  isOrganizationAllowed(author) {
    // Always allow explicitly whitelisted organizations
    if (this.config.allowedOrganizations.includes(author)) {
      return true;
    }

    // Trusted verified organizations on Hugging Face
    const trustedOrgs = [
      'google', 'facebook', 'microsoft', 'openai',
      'huggingface', 'meta-llama', 'stabilityai'
    ];

    return trustedOrgs.includes(author.toLowerCase());
  }

  async verifyModelSignature(repoId, repoInfo) {
    // Check for signed commits
    try {
      const commits = await axios.get(
        `https://huggingface.co/api/models/${repoId}/commits/main`,
        { timeout: 10000 }
      );

      const latestCommit = commits.data[0];

      // Verify GPG signature if available
      if (!latestCommit.signature) {
        console.warn(`Model ${repoId} does not have signed commits`);

        if (this.config.requireSignedModels) {
          throw new SecurityError(
            'Model commits are not GPG signed',
            'UNSIGNED_MODEL'
          );
        }
      }

      return true;
    } catch (error) {
      if (error instanceof SecurityError) throw error;
      console.warn(`Could not verify signature for ${repoId}: ${error.message}`);
      return !this.config.requireSignedModels;
    }
  }

  async performSecurityScan(modelPath, repoId) {
    const threats = [];
    const scannedFiles = [];

    const files = await this.walkDirectory(modelPath);

    for (const file of files) {
      const ext = path.extname(file).toLowerCase();
      const relativePath = path.relative(modelPath, file);

      // Check for blocked file types
      if (this.blockedFileTypes.includes(ext)) {
        threats.push(`Potentially unsafe file type: ${relativePath}`);
        continue;
      }

      // Scan text-based files for malicious patterns
      if (['.json', '.py', '.js', '.yaml', '.yml', '.txt', '.md'].includes(ext)) {
        const content = await fs.readFile(file, 'utf-8');

        for (const pattern of this.maliciousPatterns) {
          if (pattern.test(content)) {
            threats.push(`Malicious pattern detected in ${relativePath}: ${pattern}`);
          }
        }

        // Check for suspicious base64 encoded content
        const base64Pattern = /[A-Za-z0-9+/]{100,}={0,2}/g;
        const base64Matches = content.match(base64Pattern) || [];

        for (const match of base64Matches) {
          try {
            const decoded = Buffer.from(match, 'base64').toString('utf-8');
            for (const pattern of this.maliciousPatterns) {
              if (pattern.test(decoded)) {
                threats.push(`Obfuscated malicious code in ${relativePath}`);
              }
            }
          } catch (e) {
            // Not valid base64, skip
          }
        }
      }

      // Analyze model config for dangerous operations
      if (file.endsWith('config.json')) {
        const configThreats = await this.scanModelConfig(file);
        threats.push(...configThreats);
      }

      scannedFiles.push(relativePath);
    }

    return {
      safe: threats.length === 0,
      threats,
      scannedFiles,
      timestamp: new Date().toISOString()
    };
  }

  async scanModelConfig(configPath) {
    const threats = [];
    const content = await fs.readFile(configPath, 'utf-8');
    const config = JSON.parse(content);

    // Check for custom code that could be malicious
    if (config.auto_map) {
      threats.push('Model uses auto_map which can load arbitrary code');
    }

    if (config.custom_pipelines) {
      threats.push('Model defines custom pipelines');
    }

    // Check for trust_remote_code patterns
    const dangerousKeys = ['trust_remote_code', 'custom_code', 'remote_code'];
    for (const key of dangerousKeys) {
      if (config[key]) {
        threats.push(`Model requires ${key} - potential code execution risk`);
      }
    }

    return threats;
  }

  async handleMaliciousModel(quarantinePath, scanResult, auditId) {
    // Emit security event for SIEM integration
    this.emit('security_threat', {
      type: 'malicious_model_detected',
      auditId,
      path: quarantinePath,
      threats: scanResult.threats,
      timestamp: new Date().toISOString()
    });

    // Log detailed threat information
    this.config.auditLog.error('SECURITY ALERT: Malicious model detected', {
      auditId,
      threats: scanResult.threats,
      action: 'quarantine_and_report'
    });

    // Keep in quarantine for analysis, don't delete
    const reportPath = path.join(quarantinePath, 'SECURITY_REPORT.json');
    await fs.writeFile(reportPath, JSON.stringify(scanResult, null, 2));
  }

  async createSecureManifest(modelPath, repoId, repoInfo) {
    const files = await this.walkDirectory(modelPath);
    const fileHashes = {};

    for (const file of files) {
      const content = await fs.readFile(file);
      const hash = crypto.createHash('sha256').update(content).digest('hex');
      fileHashes[path.relative(modelPath, file)] = hash;
    }

    const manifest = {
      repoId,
      version: repoInfo.sha,
      downloadedAt: new Date().toISOString(),
      files: fileHashes,
      totalHash: crypto.createHash('sha256')
        .update(JSON.stringify(fileHashes))
        .digest('hex')
    };

    const manifestPath = path.join(modelPath, 'SECURE_MANIFEST.json');
    await fs.writeFile(manifestPath, JSON.stringify(manifest, null, 2));

    return manifest;
  }

  async walkDirectory(dir) {
    const files = [];
    const entries = await fs.readdir(dir, { withFileTypes: true });

    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        files.push(...await this.walkDirectory(fullPath));
      } else {
        files.push(fullPath);
      }
    }
    return files;
  }

  auditLog(event, data) {
    const logEntry = {
      event,
      ...data,
      service: 'secure-model-hub',
      environment: process.env.NODE_ENV || 'development'
    };

    if (this.config.auditLog.info) {
      this.config.auditLog.info(JSON.stringify(logEntry));
    } else {
      console.log(JSON.stringify(logEntry));
    }
  }
}

class SecurityError extends Error {
  constructor(message, code) {
    super(message);
    this.name = 'SecurityError';
    this.code = code;
  }
}

// Production usage with monitoring
const client = new SecureModelHubClient({
  allowedOrganizations: ['my-company', 'trusted-partner'],
  requireSignedModels: true,
  huggingFaceToken: process.env.HF_TOKEN,
  auditLog: require('./logger')
});

// Listen for security events
client.on('security_threat', (event) => {
  // Send to SIEM/security monitoring
  alertSecurityTeam(event);
});

try {
  const { path: modelPath, manifest } = await client.fetchModelSecurely(
    'google/bert-base-uncased'
  );
  console.log(`Model verified: ${manifest.totalHash}`);
} catch (error) {
  if (error instanceof SecurityError) {
    console.error(`Security violation: ${error.code} - ${error.message}`);
  }
}
```

**Defense in Depth Layers**:

1. **Organization Allowlisting**: Only models from verified organizations can be loaded
```javascript
if (!this.isOrganizationAllowed(repoInfo.author)) {
  throw new SecurityError('Unauthorized organization', 'UNAUTHORIZED_ORG');
}
```

2. **Cryptographic Verification**: GPG-signed commits and SHA-256 file hashing ensure integrity
```javascript
const hash = crypto.createHash('sha256').update(content).digest('hex');
fileHashes[path.relative(modelPath, file)] = hash;
```

3. **Deep Content Scanning**: Pattern matching for malicious code including obfuscated payloads
```javascript
for (const pattern of this.maliciousPatterns) {
  if (pattern.test(content)) {
    threats.push(`Malicious pattern detected: ${pattern}`);
  }
}
```

**Additional Protections**:
- **Quarantine workflow**: Models are downloaded to isolated directory for scanning before approval
- **Blocked file types**: Pickle files (.pkl, .pt, .pth) that can execute arbitrary Python are rejected
- **Trust boundary enforcement**: Models requiring `trust_remote_code` are blocked by default
- **Comprehensive audit logging**: All model operations logged for forensic analysis
- **SIEM integration**: Security events emitted for real-time threat detection
- **Manifest tracking**: Cryptographic manifest enables future integrity verification
